        for (int j = 0; j < n; ++j) {
            if (grid[i][j] > 0 && !visited[i][j]) {
                // BFS
                std::queue<std::pair<int, int>> q;
                q.push({i, j});
                visited[i][j] = true;
                long long sum = grid[i][j];

                while (!q.empty()) {
                    int x = q.front().first;
                    int y = q.front().second;
                    q.pop();

                    // Check all four directions
                    int dx[] = {-1, 1, 0, 0};
                    int dy[] = {0, 0, -1, 1};

                    for (int d = 0; d < 4; ++d) {
                        int nx = x + dx[d];
                        int ny = y + dy[d];
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && !visited[nx][ny] && grid[nx][ny] > 0) {
                            visited[nx][ny] = true;
                            sum += grid[nx][ny];
                            q.push({nx, ny});
                        }
                    }
                }
                // Check if sum is divisible by k
                if (sum % k == 0) {
                    ++count;
                }
            }
        }
    }
    return count;
}

